function check_setTopNPools_owner_access(address[] calldata pools) public {
    // Setup: caller is owner
    vm.assume(msg.sender == strategy.owner());
    vm.assume(msg.sender != strategy.executor());

    // This should NOT revert - owner should have access
    // Bug: onlyExecutor modifier blocks owner
    strategy.setTopNPools(pools);

    // If we reach here, owner access is correctly allowed
    assert(true);
}
